create table if not exists public.btp_connection_keyword_rule (
    rule_id bigserial primary key,
    keyword varchar(100) not null,
    function_name varchar(100) not null,
    equipment_category_large varchar(100),
    equipment_category_middle varchar(100),
    evidence_template varchar(500) not null,
    confidence numeric(4, 3) not null default 0.700,
    generated_by varchar(50) not null default 'manual',
    reviewed boolean not null default true,
    active boolean not null default true,
    created_at timestamp without time zone not null default now(),
    updated_at timestamp without time zone not null default now(),
    constraint ck_btp_connection_keyword_rule_confidence check (confidence >= 0 and confidence <= 1),
    constraint uk_btp_connection_keyword_rule unique (
        keyword,
        function_name,
        equipment_category_large,
        equipment_category_middle
    )
);

comment on table public.btp_connection_keyword_rule is 'BTP 솔루션 3번 연결 근거용 기업/제품 키워드-기능-장비분류 매핑 규칙';
comment on column public.btp_connection_keyword_rule.keyword is '기업 주요제품, 지원품목, NTIS 과제명 등에서 찾을 키워드';
comment on column public.btp_connection_keyword_rule.function_name is '화면에 표시할 연결 기능명';
comment on column public.btp_connection_keyword_rule.equipment_category_large is '연결 대상 장비 대분류. null이면 대분류 제한 없음';
comment on column public.btp_connection_keyword_rule.equipment_category_middle is '연결 대상 장비 중분류. null이면 중분류 제한 없음';
comment on column public.btp_connection_keyword_rule.evidence_template is '연결 근거 문장. 화면에서 2줄로 표시할 수 있도록 줄바꿈을 포함';
comment on column public.btp_connection_keyword_rule.confidence is 'AI 초안 규칙 신뢰도. 서비스 적용 전 검수 참고값';
comment on column public.btp_connection_keyword_rule.generated_by is '규칙 생성 주체. 예: codex-ai-draft, human';
comment on column public.btp_connection_keyword_rule.reviewed is '사람 검수 완료 여부. 운영 API는 true 규칙만 사용하는 것을 권장';

create index if not exists idx_btp_connection_keyword_rule_active
    on public.btp_connection_keyword_rule (active, reviewed);

create index if not exists idx_btp_connection_keyword_rule_keyword
    on public.btp_connection_keyword_rule (keyword);

create index if not exists idx_btp_connection_keyword_rule_equipment_category
    on public.btp_connection_keyword_rule (equipment_category_large, equipment_category_middle);

-- Candidate seed rows generated by scripts/mine_btp_connection_keyword_rules.py
-- Evidence templates are stored as two display lines separated by a newline.
insert into public.btp_connection_keyword_rule (
    keyword, function_name, equipment_category_large, equipment_category_middle,
    evidence_template, confidence, generated_by, reviewed, active
)
values
    ('가스', '성분/분석시험', '화합물전처리/분석장비', null, E'''KSIC 29 기타 기계 및 장비 제조업''의 산업 계층을 훑어보면 ''가스'' 단서가 17건 반복됩니다.\n장비 수 36건과 거점 수 5건을 동시에 고려해 ''성분/분석시험''을 검토 대상으로 유지했습니다.', 0.970, 'codex-miner', true, true),
    ('가스', '전기, 가스, 증기 및 공기 조절 공급업 맞춤 측정시험 활용', '전기/전자장비', '측정시험장비', E'KSIC 산업 계층 기준으로 ''가스''가 10건 축적되어 ''KSIC 35 전기, 가스, 증기 및 공기 조절 공급업''의 장비 연결 근거가 됩니다.\n전기/전자장비 > 측정시험장비에 속한 장비군이 확인되므로 ''전기, 가스, 증기 및 공기 조절 공급업 맞춤 측정시험 활용''은 단순 키워드 매칭을 넘어선 추천 후보입니다.', 0.970, 'codex-miner', true, true),
    ('가스', '전기, 가스, 증기 및 공기 조절 공급업 맞춤 환경조성/생산/사육시설 검증/활용', '환경조성/생산/사육시설장비', null, E'10개 항목에 나타난 ''가스''를 기준으로 ''KSIC 35 전기, 가스, 증기 및 공기 조절 공급업''의 연결 가능한 장비군을 탐색했습니다.\n최종 판단은 산업 키워드-장비 분류 프로파일, 장비 26건, 신뢰도 0.970를 함께 반영한 결과입니다.', 0.970, 'codex-miner', true, true),
    ('고무', '고무 및 플라스틱제품 제조업 맞춤 재료물성시험 활용', '기계가공/시험장비', '재료물성시험장비', E'''고무'' 단서는 ''KSIC 22 고무 및 플라스틱제품 제조업''의 분류 설명과 세부 항목에서 반복적으로 확인됩니다.\n기계가공/시험장비 > 재료물성시험장비에 속한 장비군이 확인되므로 ''고무 및 플라스틱제품 제조업 맞춤 재료물성시험 활용''은 단순 키워드 매칭을 넘어선 추천 후보입니다.', 0.970, 'codex-miner', true, true),
    ('공기', '전기, 가스, 증기 및 공기 조절 공급업 맞춤 데이터처리 검증/활용', '데이터처리장비', null, E'''KSIC 35 전기, 가스, 증기 및 공기 조절 공급업''의 원천 문맥에서 ''공기'' 단서가 포착되어 기능 추천 후보의 근거로 삼았습니다.\n데이터처리장비 전반의 장비 풀과 산업 단서가 동시에 확인되어 ''전기, 가스, 증기 및 공기 조절 공급업 맞춤 데이터처리 검증/활용'' 연결 근거가 성립합니다.', 0.970, 'codex-miner', true, true),
    ('관제', '데이터/실감형 콘텐츠 검증', '데이터처리장비', null, E'KSIC 산업 계층의 반복 출현 양상을 기준으로 ''관제''를 ''KSIC 24 1차 금속 제조업''의 장비 수요 단서로 분류했습니다.\nBTP 인프라 관점에서는 데이터처리장비 전반가 핵심 장비 범위이며, ''데이터/실감형 콘텐츠 검증''의 근거 장비는 29건입니다.', 0.970, 'codex-miner', true, true),
    ('광학', '의료, 정밀, 광학 기기 및 시계 제조업 맞춤 광학/전자영상 활용', '광학/전자영상장비', null, E'''KSIC 27 의료, 정밀, 광학 기기 및 시계 제조업''의 산업 계층을 훑어보면 ''광학'' 단서가 19건 반복됩니다.\n산업 키워드-장비 분류 프로파일 결과가 48개 장비로 뒷받침되어 ''의료, 정밀, 광학 기기 및 시계 제조업 맞춤 광학/전자영상 활용''을 객관적 연결안으로 채택했습니다.', 0.970, 'codex-miner', true, true),
    ('교육', '교육 서비스업 맞춤 데이터처리 검증/활용', '데이터처리장비', null, E'''교육''는 ''KSIC 85 교육 서비스업''에서 확인된 산업 용어이며, 장비 후보군 선별을 위한 1차 기준으로 사용했습니다.\n데이터처리장비 전반 장비군을 기준으로 볼 때 ''교육 서비스업 맞춤 데이터처리 검증/활용''은 산업 단서와 장비 자원의 접점이 분명합니다.', 0.970, 'codex-miner', true, true),
    ('구성', '구성 관련 장비 검증', '기계가공/시험장비', '자동화/이송 장비', E'KSIC 산업 계층의 반복 출현 양상을 기준으로 ''구성''를 ''KSIC 27 의료, 정밀, 광학 기기 및 시계 제조업''의 장비 수요 단서로 분류했습니다.\n분류 범위가 기계가공/시험장비 > 자동화/이송 장비로 수렴하고 장비 수가 52건이라 ''구성 관련 장비 검증'' 근거가 비교적 명확합니다.', 0.970, 'codex-miner', true, true),
    ('구조', '금속 가공제품 제조업; 기계 및 가구 제외 맞춤 광학/전자영상 활용', '광학/전자영상장비', null, E'''KSIC 25 금속 가공제품 제조업; 기계 및 가구 제외''의 원천 문맥에서 ''구조'' 단서가 포착되어 기능 추천 후보의 근거로 삼았습니다.\n산업 키워드-장비 분류 프로파일 기준을 적용해 장비 범위를 광학/전자영상장비 전반로 제한하고, 신뢰도 0.970로 ''금속 가공제품 제조업; 기계 및 가구 제외 맞춤 광학/전자영상 활용''을 정리했습니다.', 0.970, 'codex-miner', true, true),
    ('구조', '금속 가공제품 제조업; 기계 및 가구 제외 맞춤 물리적측정 활용', '물리적측정장비', null, E'''구조'' 단서는 ''KSIC 25 금속 가공제품 제조업; 기계 및 가구 제외''의 분류 설명과 세부 항목에서 반복적으로 확인됩니다.\n장비 후보는 물리적측정장비 전반 중심으로 제한했고, 8개 거점 분포가 활용 가능성을 보강합니다.', 0.970, 'codex-miner', true, true),
    ('금속', '금속 가공제품 제조업; 기계 및 가구 제외 맞춤 광학/전자영상 활용', '광학/전자영상장비', null, E'''KSIC 25 금속 가공제품 제조업; 기계 및 가구 제외''에서 ''금속''가 확인된 항목 수는 33개이며, 기능 연결 검토에 충분한 밀도를 보입니다.\n신뢰도 0.970, 장비 48건, 거점 11건을 함께 반영해 ''금속 가공제품 제조업; 기계 및 가구 제외 맞춤 광학/전자영상 활용'' 근거로 채택했습니다.', 0.970, 'codex-miner', true, true),
    ('기기', '의료, 정밀, 광학 기기 및 시계 제조업 맞춤 임상의료 검증/활용', '임상의료장비', null, E'''KSIC 27 의료, 정밀, 광학 기기 및 시계 제조업''를 기준으로 보면 ''기기''는 장비 연결 여부를 검토할 만큼 충분히 반복된 단서입니다.\n산업 키워드-장비 분류 프로파일 방식으로 확인한 장비군은 임상의료장비 전반이며, 최종 신뢰도는 0.970로 산정했습니다.', 0.970, 'codex-miner', true, true),
    ('달리', '달리 관련 장비 검증', '물리적측정장비', '힘/토오크/압력/진공측정장비', E'검토 범위는 ''KSIC 29 기타 기계 및 장비 제조업''이며, KSIC 산업 계층에서 ''달리'' 단서가 7건 확인됐습니다.\n물리적측정장비 > 힘/토오크/압력/진공측정장비 장비군을 기준으로 볼 때 ''달리 관련 장비 검증''은 산업 단서와 장비 자원의 접점이 분명합니다.', 0.970, 'codex-miner', true, true),
    ('디지털', '디지털 관련 장비 검증', '임상의료장비', '임상측정/진단장비', E'KSIC 산업 계층에 나타난 ''디지털''의 반복 횟수와 분포를 함께 보아 산업 수요 단서로 판단했습니다.\n신뢰도 0.970와 임상의료장비 > 임상측정/진단장비 장비 분포를 함께 반영해 ''디지털 관련 장비 검증''의 우선순위를 부여했습니다.', 0.970, 'codex-miner', true, true),
    ('모니터', '모니터 관련 장비 검증', '임상의료장비', '임상측정/진단장비', E'''모니터''는 ''KSIC 26 전자 부품, 컴퓨터, 영상, 음향 및 통신장비 제조업''의 산업명 또는 하위 설명과 맞물려 의미 있는 매칭 출발점이 됩니다.\n신뢰도 0.970와 임상의료장비 > 임상측정/진단장비 장비 분포를 함께 반영해 ''모니터 관련 장비 검증''의 우선순위를 부여했습니다.', 0.970, 'codex-miner', true, true),
    ('물질', '의료용 물질 및 의약품 제조업 맞춤 화합물전처리/분석 활용', '화합물전처리/분석장비', null, E'''KSIC 21 의료용 물질 및 의약품 제조업''를 기준으로 보면 ''물질''는 장비 연결 여부를 검토할 만큼 충분히 반복된 단서입니다.\n화합물전처리/분석장비 전반의 36개 장비와 5개 거점 분포를 근거로 ''의료용 물질 및 의약품 제조업 맞춤 화합물전처리/분석 활용'' 후보를 채택했습니다.', 0.970, 'codex-miner', true, true),
    ('물질', '화학 물질 및 화학제품 제조업; 의약품 제외 맞춤 화합물전처리/분석 활용', '화합물전처리/분석장비', null, E'원천은 KSIC 산업 계층, 범위는 ''KSIC 20 화학 물질 및 화학제품 제조업; 의약품 제외''이며 ''물질'' 단서가 31건의 판단 근거를 제공합니다.\n산업 키워드-장비 분류 프로파일 결과가 36개 장비로 뒷받침되어 ''화학 물질 및 화학제품 제조업; 의약품 제외 맞춤 화합물전처리/분석 활용''을 객관적 연결안으로 채택했습니다.', 0.970, 'codex-miner', true, true),
    ('방사', '전자파시험(EMC)', '전기/전자장비', '측정시험장비', E'KSIC 산업 계층에서 포착된 ''방사''는 8개 항목에 분산되어 단발 표현으로 보기 어렵습니다.\n분류 범위가 전기/전자장비 > 측정시험장비로 수렴하고 장비 수가 24건이라 ''전자파시험(EMC)'' 근거가 비교적 명확합니다.', 0.970, 'codex-miner', true, true),
    ('방식', '방식 관련 장비 검증', '임상의료장비', '임상측정/진단장비', E'''KSIC 29 기타 기계 및 장비 제조업''의 계층 정보에서 ''방식''가 안정적으로 확인되어 장비 매칭 검토 대상으로 올렸습니다.\n41개 장비가 임상의료장비 > 임상측정/진단장비 안에 묶여 있어 ''방식 관련 장비 검증'' 연결의 설명력을 확보했습니다.', 0.970, 'codex-miner', true, true),
    ('밸브', '기타 기계 및 장비 제조업 맞춤 물리적측정 활용', '물리적측정장비', null, E'''밸브'' 단서는 ''KSIC 29 기타 기계 및 장비 제조업''의 분류 설명과 세부 항목에서 반복적으로 확인됩니다.\n물리적측정장비 전반 범위 안에서 장비 70건이 확인되어 ''기타 기계 및 장비 제조업 맞춤 물리적측정 활용'' 추천의 장비 기반이 충분합니다.', 0.970, 'codex-miner', true, true),
